    // --- Piecewise Polynomial Helpers (Generated) ---
    template <typename T, int N_BREAKS, int DEG>
    static inline T ppoly_eval(
        const T& s,
        const std::array<double, N_BREAKS>& breaks,
        const std::array<double, (N_BREAKS - 1) * (DEG + 1)>& coeffs)
    {
        static_assert(N_BREAKS >= 2, "ppoly requires >= 1 segment");
        constexpr int N_SEG = N_BREAKS - 1;
        const double sd = static_cast<double>(s);

        int seg = 0;
        if (sd <= breaks[0]) {
            seg = 0;
        } else if (sd >= breaks[N_BREAKS - 1]) {
            seg = N_SEG - 1;
        } else {
            int lo = 0;
            int hi = N_BREAKS - 1;
            while (hi - lo > 1) {
                const int mid = (lo + hi) / 2;
                if (sd < breaks[mid]) {
                    hi = mid;
                } else {
                    lo = mid;
                }
            }
            seg = lo;
        }

        const T t = s - T(breaks[seg]);
        const double* c = coeffs.data() + seg * (DEG + 1);

        T y = T(c[0]);
        for (int i = 1; i < (DEG + 1); ++i) {
            y = y * t + T(c[i]);
        }
        return y;
    }

