    template <typename T>
    static MSVec<T, NX> rk4_step(
        const MSVec<T, NX>& x,
        const MSVec<T, NU>& u,
        const MSVec<T, NP>& p,
        double dt,
        MSMat<T, NX, NX>* A,
        MSMat<T, NX, NU>* B)
    {
        MSVec<T, NX> k1;
        MSVec<T, NX> k2;
        MSVec<T, NX> k3;
        MSVec<T, NX> k4;
        MSMat<T, NX, NX> fx1;
        MSMat<T, NX, NX> fx2;
        MSMat<T, NX, NX> fx3;
        MSMat<T, NX, NX> fx4;
        MSMat<T, NX, NU> fu1;
        MSMat<T, NX, NU> fu2;
        MSMat<T, NX, NU> fu3;
        MSMat<T, NX, NU> fu4;
        MSMat<T, NX, NX> I;
        MatOps::setIdentity(I);

        continuous_eval(x, u, p, k1, fx1, fu1);
        const MSVec<T, NX> x2 = x + k1 * (0.5 * dt);
        const MSMat<T, NX, NX> dx2_dx = I + fx1 * (0.5 * dt);
        const MSMat<T, NX, NU> dx2_du = fu1 * (0.5 * dt);

        continuous_eval(x2, u, p, k2, fx2, fu2);
        const MSMat<T, NX, NX> dk2_dx = fx2 * dx2_dx;
        const MSMat<T, NX, NU> dk2_du = fx2 * dx2_du + fu2;

        const MSVec<T, NX> x3 = x + k2 * (0.5 * dt);
        const MSMat<T, NX, NX> dx3_dx = I + dk2_dx * (0.5 * dt);
        const MSMat<T, NX, NU> dx3_du = dk2_du * (0.5 * dt);

        continuous_eval(x3, u, p, k3, fx3, fu3);
        const MSMat<T, NX, NX> dk3_dx = fx3 * dx3_dx;
        const MSMat<T, NX, NU> dk3_du = fx3 * dx3_du + fu3;

        const MSVec<T, NX> x4 = x + k3 * dt;
        const MSMat<T, NX, NX> dx4_dx = I + dk3_dx * dt;
        const MSMat<T, NX, NU> dx4_du = dk3_du * dt;

        continuous_eval(x4, u, p, k4, fx4, fu4);
        const MSMat<T, NX, NX> dk4_dx = fx4 * dx4_dx;
        const MSMat<T, NX, NU> dk4_du = fx4 * dx4_du + fu4;

        if (A != nullptr) {
            *A = I + (fx1 + dk2_dx * 2.0 + dk3_dx * 2.0 + dk4_dx) * (dt / 6.0);
        }
        if (B != nullptr) {
            *B = (fu1 + dk2_du * 2.0 + dk3_du * 2.0 + dk4_du) * (dt / 6.0);
        }

        return x + (k1 + k2 * 2.0 + k3 * 2.0 + k4) * (dt / 6.0);
    }


